function solve(points, target) {
    // Helper function to check if a point exists in a set of points (represented by a Set of string keys)
    const pointToString = (p) => p.join(',');
    const targetString = target.join(',');

    // --- Generation Process ---

    // pointsSet will store all unique points generated so far (from generation 0 up to the current one)
    // We use a Set for efficient lookup of existing points.
    let currentPoints = points.map(p => p.slice()); // Start with a mutable copy of initial points
    let pointsSet = new Set();

    // Initialize with points from generation 0
    for (const p of points) {
        const pStr = pointToString(p);
        if (!pointsSet.has(pStr)) {
            pointsSet.add(pStr);
        }
    }

    // Check for target in Generation 0
    if (pointsSet.has(targetString)) {
        return 0;
    }

    let k = 0;
    let generatedInPreviousStep = true; // Flag to continue generation until no new points are generated or target is found

    while (generatedInPreviousStep) {
        k++;
        generatedInPreviousStep = false;

        const newPoints = [];
        const uniqueNewPointsStrings = new Set();

        // Convert currentPoints array to a list of unique coordinates for pairing,
        // as currentPoints might contain duplicates if the problem description implies
        // that the list grows by adding all generated points, even if coordinates repeat.
        // However, the generation rule states: "consider from generation 0 to k-1...".
        // Since pointsSet holds all unique points available up to generation k-1, we iterate over them.

        const availablePoints = Array.from(pointsSet).map(str => str.split(',').map(Number));
        const n = availablePoints.length;

        if (n < 2) {
            // If less than 2 unique points are available, no new pairs can be formed.
            break;
        }

        // Generate new points by pairing every pair of *different* available points
        for (let i = 0; i < n; i++) {
            for (let j = i + 1; j < n; j++) {
                const p1 = availablePoints[i];
                const p2 = availablePoints[j];

                // Check the "different points" constraint: they must have different coordinates.
                // Since we are iterating over unique coordinates stored in pointsSet,
                // p1 and p2 are guaranteed to be distinct in coordinate space, UNLESS 
                // the input points had duplicates, but the prompt says: "Initial point set does not contain duplicates."
                // Since availablePoints is derived from pointsSet, p1 and p2 have distinct coordinates.
                // The constraint: "The two different points must have different (x, y, z) coordinates."
                // If we iterate over unique points, this is satisfied.

                const newP = [
                    Math.floor((p1[0] + p2[0]) / 2),
                    Math.floor((p1[1] + p2[1]) / 2),
                    Math.floor((p1[2] + p2[2]) / 2)
                ];
                const newPStr = pointToString(newP);

                if (!pointsSet.has(newPStr)) {
                    uniqueNewPointsStrings.add(newPStr);
                    newPoints.push(newP);
                }
            }
        }

        // Add all newly generated unique points to the master set
        if (newPoints.length > 0) {
            generatedInPreviousStep = true;
            for (const p of newPoints) {
                pointsSet.add(pointToString(p));

                // Check if the target was just generated
                if (pointToString(target) === pointToString(p)) {
                    return k;
                }
            }
        }

        // If no new unique points were generated in this step, we stop the loop.
        if (!generatedInPreviousStep && newPoints.length === 0) {
             break;
        }
    }

    // If the loop finishes and the target hasn't been found
    return -1;
}

